const items = $input.all();
const item = items[0];
let trigger = {};
try { trigger = $('Telegram Trigger').first().json || {}; } catch (e) {}
const cq = trigger.callback_query || {};
let settings = {};
try { settings = JSON.parse((item && item.json && item.json.settingsRaw) || '{}'); } catch (e) {}
if (!Array.isArray(settings.channels)) settings.channels = [];
if (settings.hitl_enabled === undefined) settings.hitl_enabled = true;
settings.hitl_enabled = !settings.hitl_enabled;
const chId = settings.channels.length > 0 ? settings.channels[0].id : '-1003856051987';
const chName = settings.channels.length > 0 ? (settings.channels[0].name || settings.channels[0].id) : 'дефолт';
const menuText = '⚙️ *Налаштування*\n\n🔧 Модерація: ' + (settings.hitl_enabled ? '✅' : '❌') + '\n📢 Канал: `' + chId + '`';
const keyboard = { inline_keyboard: [
  [{ text: '🔧 HITL: ' + (settings.hitl_enabled ? '✅' : '❌'), callback_data: 'toggle_hitl' }],
  [{ text: '📢 Змінити канал', callback_data: 'change_channel' }],
  [{ text: '📋 Список', callback_data: 'list_channels' }],
  [{ text: '❌ Закрити', callback_data: 'close_settings' }]
] };
return [{ json: { settingsToSave: JSON.stringify(settings), userId: cq.from && cq.from.id, chatId: cq.message && cq.message.chat && cq.message.chat.id, messageId: cq.message && cq.message.message_id, callbackId: cq.id, menuText, keyboardJson: JSON.stringify(keyboard) } }];

let trigger = {};
try { trigger = $('Telegram Trigger').first().json || {}; } catch (e) {}
const cq = trigger.callback_query || {};
return [{ json: { userId: cq.from && cq.from.id, chatId: cq.message && cq.message.chat && cq.message.chat.id, callbackId: cq.id } }];

const items = $input.all();
const item = items[0];
let trigger = {};
try { trigger = $('Telegram Trigger').first().json || {}; } catch (e) {}
const cq = trigger.callback_query || {};
let settings = {};
try { settings = JSON.parse((item && item.json && item.json.settingsRaw) || '{}'); } catch (e) {}
if (!Array.isArray(settings.channels)) settings.channels = [];

const DEFAULT_CHANNEL = '-1003856051987';

let text = '📋 *Канали*\n\n';
if (!settings.channels.length) {
  // Show default channel as the active one
  text += '🟢 `' + DEFAULT_CHANNEL + '` _(дефолт)_';
} else {
  for (let i = 0; i < settings.channels.length; i++) {
    const ch = settings.channels[i];
    text += (i === 0 ? '🟢 ' : '⚪ ') + '`' + ch.id + '`';
    if (ch.name) text += ' — ' + ch.name;
    text += '\n';
  }
}

return [{ json: {
  chatId: cq.message && cq.message.chat && cq.message.chat.id,
  callbackId: cq.id,
  text
} }];

let trigger = {};
try { trigger = $('Telegram Trigger').first().json || {}; } catch (e) {}
const cq = trigger.callback_query || {};
return [{ json: { chatId: cq.message && cq.message.chat && cq.message.chat.id, messageId: cq.message && cq.message.message_id, callbackId: cq.id } }];

const inputs = $input.all();
let trigger = {};
try { trigger = $('Telegram Trigger').first().json || {}; } catch (e) {}
const text = (trigger.message && trigger.message.text) || '';
const parts = text.trim().split(/\s+/);
const cmd = (parts[0] || '').toLowerCase();
const chatId = (trigger.message && trigger.message.chat && trigger.message.chat.id) || 0;
const tgUserId = (trigger.message && trigger.message.from && trigger.message.from.id) || 0;
const userId = 'asst_' + tgUserId;
const sessionId = 'session_' + chatId;

const item = inputs[0] || { json: {} };
let settings = {};
try { settings = JSON.parse(item.json.settingsRaw || '{}'); } catch (e) {}
if (!Array.isArray(settings.channels)) settings.channels = [];
if (settings.hitl_enabled === undefined) settings.hitl_enabled = true;

const chId = settings.channels.length > 0 ? settings.channels[0].id : '-1003856051987';
const chName = settings.channels.length > 0 ? (settings.channels[0].name || chId) : chId;

let cmdType = 'unknown';
let reply = '';
let keyboardObj = null;

if (cmd.startsWith('/settings')) {
  cmdType = 'settings';
  reply = '⚙️ *Налаштування*\n\n🔧 Модерація: ' + (settings.hitl_enabled ? '✅' : '❌') + '\n📢 Канал: `' + chId + '`';
  keyboardObj = { inline_keyboard: [
    [{ text: '🔧 HITL: ' + (settings.hitl_enabled ? '✅' : '❌'), callback_data: 'toggle_hitl' }],
    [{ text: '📢 Змінити канал', callback_data: 'change_channel' }],
    [{ text: '📋 Список каналів', callback_data: 'list_channels' }],
    [{ text: '❌ Закрити', callback_data: 'close_settings' }]
  ] };
} else if (cmd.startsWith('/channel')) {
  cmdType = 'channel';
  reply = '📢 *Поточний канал для публікацій*\n\n`' + chId + '`' + (chName !== chId ? '\n' + chName : '');
  keyboardObj = { inline_keyboard: [
    [{ text: '🔄 Змінити канал', callback_data: 'change_channel' }],
    [{ text: '📋 Список каналів', callback_data: 'list_channels' }],
    [{ text: '❌ Закрити', callback_data: 'close_settings' }]
  ] };
} else if (cmd === '/memory') {
  cmdType = 'memory';
  reply = '';
} else if (cmd === '/reset') {
  cmdType = 'reset';
  reply = '';
}

return [{ json: {
  cmdType, replyText: reply, chatId, userId, sessionId,
  keyboardJson: keyboardObj, hasKeyboard: !!keyboardObj
} }];

const items = $input.all();
const item = items[0];
const binEntry = item && item.binary && item.binary.data;
if (!binEntry) throw new Error('No binary photo data');
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');
let msg = {};
try { msg = $('Telegram Trigger').first().json.message || {}; } catch (e) {}
const groupId = msg.media_group_id || '';
const myRequestId = Date.now() + '_' + Math.random().toString(36).slice(2, 10);
const mime = binEntry.mimeType || 'image/jpeg';
return [{ json: { imageDataUrl: 'data:' + mime + ';base64,' + base64, imageMime: mime, isAlbum: !!groupId, mediaGroupId: groupId, myRequestId }, binary: item.binary }];

const items = $input.all();
const item = items[0];
const imageDataUrl = item && item.json && item.json.imageDataUrl;
if (!imageDataUrl) throw new Error('No imageDataUrl');
const body = { model: 'gpt-5-mini', messages: [{ role: 'user', content: [
  { type: 'text', text: 'Опиши українською для SMM. JSON: description, objects, mood, smm_topics, quality' },
  { type: 'image_url', image_url: { url: imageDataUrl } }
]}], response_format: { type: 'json_object' } };
return [{ json: { visionBody: JSON.stringify(body) } }];

let setup = {};
try { setup = $('Setup Prompt').first().json || {}; } catch (e) {}
const userMessage = (setup.userMessage || '').trim();
const chatId = setup.chatId;
if (userMessage === '/cancel') return [{ json: { replyText: '🚫 Скасовано.', chatId, settingsToSave: null } }];
if (!userMessage.match(/^-?\d+$/)) return [{ json: { replyText: '❌ Не схоже на chat_id. /cancel — скасувати.', chatId, settingsToSave: null } }];
const userId = setup.userId ? setup.userId.replace('asst_', '') : '';
return [{ json: { chatId, userId, newChannelId: userMessage } }];

const items = $input.all();
const item = items[0];
let proc = {};
try { proc = $('Channel Input Process').first().json || {}; } catch (e) {}
let settings = {};
try { settings = JSON.parse((item && item.json && item.json.settingsRaw) || '{}'); } catch (e) {}
if (!Array.isArray(settings.channels)) settings.channels = [];
if (settings.hitl_enabled === undefined) settings.hitl_enabled = true;
const newId = proc.newChannelId;
if (settings.channels.length > 0) settings.channels[0] = { id: newId, name: settings.channels[0].name || 'Канал' };
else settings.channels.push({ id: newId, name: 'Канал' });
return [{ json: { settingsToSave: JSON.stringify(settings), userId: proc.userId, chatId: proc.chatId, replyText: '✅ Канал оновлено: `' + newId + '`' } }];

let setup = {};
try { setup = $('Setup Prompt').first().json || {}; } catch (e) {}
const items = $input.all();
const first = items[0];
const settingsRaw = (first && first.json && first.json.settingsRaw) || null;
let settings = {};
try { if (settingsRaw) settings = JSON.parse(settingsRaw); } catch (e) {}
const hitlEnabled = settings.hitl_enabled !== false;
const channels = Array.isArray(settings.channels) ? settings.channels : [];
const defaultChannel = '-1003856051987';
const publishChannelId = channels.length > 0 ? channels[0].id : defaultChannel;
const publishChannelName = channels.length > 0 ? (channels[0].name || channels[0].id) : 'дефолт';
return [{ json: Object.assign({}, setup, { hitlEnabled, publishChannelId, publishChannelName, channelCount: channels.length }) }];

const inputs = $input.all();
const item = inputs[0];
let setup = {};
try { setup = $('Setup Prompt').first().json || {}; } catch (e) {}
const userMessage = setup.userMessage || '';
const output = (item && item.json && item.json.output) || '';
const body = { messages: [
  { role: 'user', name: 'HUMAN', content: userMessage },
  { role: 'assistant', name: 'AI', content: output }
]};
return [{ json: { zepBody: JSON.stringify(body) } }];

let out = '';
try { out = $('AI Agent').first().json.output || ''; } catch (e) {}
const m = out.match(/\[IMAGE_EDIT:\s*([^\]]+)\]/i);
const inner = m ? m[1].trim() : 'edit';
const parts = inner.split(/\s*\|\s*/);
const imagePrompt = parts[0].trim();
const sizeMap = { square: '1024x1024', portrait: '1024x1536', landscape: '1536x1024', auto: 'auto' };
let imageSize = '1024x1024', imageQuality = 'medium', imageN = 1;
if (parts.length > 1) {
  const opts = [...parts.slice(1).join(' ').matchAll(/(\w+)=(\S+)/g)];
  for (const o of opts) { const k = o[1].toLowerCase(); let v = o[2];
    if (k === 'size') imageSize = sizeMap[v.toLowerCase()] || v;
    else if (k === 'quality') imageQuality = v.toLowerCase();
    else if (k === 'n') imageN = Math.min(Math.max(parseInt(v) || 1, 1), 4);
  }
}
const hasPublish = /\[PUBLISH\]/i.test(out);
let caption = out.replace(/\[IMAGE_EDIT:[^\]]*\]/gi, '').replace(/\[PUBLISH\]/gi, '').trim();
return [{ json: { imagePrompt, imageSize, imageQuality, imageN, caption, hasPublish } }];

const items = $input.all();
let caption = '', hasPublish = false;
try { const ext = $('Extract Edit Prompt').first().json; caption = ext.caption || ''; hasPublish = ext.hasPublish || false; } catch (e) {}
const out = [];
for (const item of items) { const dataArr = (item.json && item.json.data) || [];
  for (let i = 0; i < dataArr.length; i++) { const b64 = dataArr[i].b64_json;
    if (!b64) continue;
    out.push({ json: { caption, hasPublish, imageIndex: i + 1, imageTotal: dataArr.length }, binary: { image: { data: b64, mimeType: 'image/png', fileName: 'edited_' + (i + 1) + '.png' } } });
  } }
if (out.length === 0) throw new Error('No images');
return out;

