  for (const o of opts) { const k = o[1].toLowerCase(); let v = o[2];
    if (k === 'size') imageSize = sizeMap[v.toLowerCase()] || v;
    else if (k === 'quality') imageQuality = v.toLowerCase();
    else if (k === 'n') imageN = Math.min(Math.max(parseInt(v) || 1, 1), 4);
  }
}
const hasPublish = /\[PUBLISH\]/i.test(out);
let caption = out.replace(/\[IMAGE:[^\]]*\]/gi, '').replace(/\[PUBLISH\]/gi, '').trim();
return [{ json: { imagePrompt, imageSize, imageQuality, imageN, caption, hasPublish } }];

const items = $input.all();
let caption = '', hasPublish = false;
try { const ext = $('Extract Gen Prompt').first().json; caption = ext.caption || ''; hasPublish = ext.hasPublish || false; } catch (e) {}
const out = [];
for (const item of items) { const dataArr = (item.json && item.json.data) || [];
  for (let i = 0; i < dataArr.length; i++) { const b64 = dataArr[i].b64_json;
    if (!b64) continue;
    out.push({ json: { caption, hasPublish, imageIndex: i + 1, imageTotal: dataArr.length }, binary: { image: { data: b64, mimeType: 'image/png', fileName: 'generated_' + (i + 1) + '.png' } } });
  } }
if (out.length === 0) throw new Error('No images');
return out;

const trigger = $('Telegram Trigger').first().json || {};
const chatId = (trigger.message && trigger.message.chat && trigger.message.chat.id) || 0;
const item = $input.first().json || {};
const edges = item.edges || [];

let reply;
if (!edges.length) {
  reply = "🧠 *Я ще не запам'ятав нічого про тебе.*\n\nНапиши «запам'ятай, що…» — і я збережу факт у довготривалу пам'ять.";
} else {
  const lines = edges.slice(0, 20).map((e, i) => {
    const fact = e.fact || e.summary || e.name || JSON.stringify(e).slice(0, 200);
    return (i + 1) + ". " + fact;
  });
  reply = "🧠 *Що я пам'ятаю про тебе:*\n\n" + lines.join("\n");
  if (edges.length > 20) reply += "\n\n_…і ще " + (edges.length - 20) + " фактів_";
}
return [{ json: { chatId, replyText: reply } }];

const trigger = $('Telegram Trigger').first().json || {};
const chatId = (trigger.message && trigger.message.chat && trigger.message.chat.id) || 0;
const reply = "✨ *Контекст поточної розмови очищено*\n\nКороткострокова пам'ять (історія чату) скинута. Довготривалі факти про тебе у ZEP залишаються — якщо хочеш видалити і їх, напиши «забудь усе про мене».";
return [{ json: { chatId, replyText: reply } }];
